before_code:
module decoder_3to8(
  input [2:0] sel,
  output [7:0] out
);
  assign out = 8'b0;
  assign out[sel] = 1'b1;
endmodule

module decoder_top();
  decoder_3to8 dec(.input(decode_sel[2:0]), .output_vec(decoded[7:0]));
endmodule

after_code:
module decoder_3to8(
  input [2:0] sel,
  output [7:0] out
);
  assign out = 8'b0;
  assign out[sel] = 1'b1;
endmodule

module decoder_top();
  decoder_3to8 dec(.sel(decode_sel[2:0]), .out(decoded[7:0]));
endmodule
